const q = $json.query || {};
const b = $json.body || {};
const action = q.action || 'questions';
const sellerId = '221081730';
const limit = q.limit || '50';
const offset = q.offset || '0';

let url = '';
let method = 'GET';
let body = {};

if (action === 'questions') {
  const status = q.status || 'UNANSWERED';
  url = `https://api.mercadolibre.com/questions/search?seller_id=${sellerId}&status=${status}&limit=${limit}&offset=${offset}&sort.field=date_created&sort.order=DESC`;
}
else if (action === 'question_detail') {
  url = `https://api.mercadolibre.com/questions/${q.question_id}`;
}
else if (action === 'answer') {
  method = 'POST';
  url = `https://api.mercadolibre.com/answers`;
  body = { question_id: Number(b.question_id || q.question_id), text: b.text || q.text };
}
else if (action === 'messages_unread') {
  url = `https://api.mercadolibre.com/messages/unread?role=seller&tag=post_sale&limit=${limit}&offset=${offset}`;
}
else if (action === 'messages_pack') {
  const mark = String(q.mark_as_read || 'false');
  url = `https://api.mercadolibre.com/messages/packs/${q.pack_id}/sellers/${sellerId}?tag=post_sale&mark_as_read=${mark}`;
}
else if (action === 'send_message') {
  method = 'POST';
  const packId = b.pack_id || q.pack_id;
  const buyerId = String(b.buyer_id || q.buyer_id || '3037204685');
  url = `https://api.mercadolibre.com/messages/packs/${packId}/sellers/${sellerId}?tag=post_sale`;
  body = { from: { user_id: String(sellerId) }, to: { user_id: buyerId }, text: b.text || q.text };
}
else if (action === 'claims') {
  const status = q.status || 'opened';
  url = `https://api.mercadolibre.com/post-purchase/v1/claims/search?stage=claim&status=${status}&limit=${limit}&offset=${offset}&sort=date_created,desc`;
}
else if (action === 'claim_detail') {
  url = `https://api.mercadolibre.com/post-purchase/v1/claims/${q.claim_id}`;
}
else if (action === 'claim_messages') {
  url = `https://api.mercadolibre.com/post-purchase/v1/claims/${q.claim_id}/messages`;
}
else if (action === 'order_detail') {
  url = `https://api.mercadolibre.com/orders/${q.order_id}`;
}
else {
  return [{ json: { error: { message: `Acción desconocida: ${action}` } } }];
}

return [{ json: { action, method, url, body, sellerId } }];
